import{_ as a,o as s,c as t,ag as e}from"./chunks/framework.Dr9kcJF8.js";const c=JSON.parse('{"title":"帖子发表工作流程","description":"","frontmatter":{},"headers":[],"relativePath":"docs/publish.md","filePath":"docs/publish.md"}'),l={name:"docs/publish.md"};function n(h,i,r,p,k,d){return s(),t("div",null,[...i[0]||(i[0]=[e(`<h1 id="帖子发表工作流程" tabindex="-1">帖子发表工作流程 <a class="header-anchor" href="#帖子发表工作流程" aria-label="Permalink to &quot;帖子发表工作流程&quot;">​</a></h1><p>转载自<a href="https://sustech-application.com/" target="_blank" rel="noreferrer">南科大飞跃手册</a></p><p>这篇文档解读飞跃手册的审稿、编辑、发布流程，为编辑们的工作提供规范化指导。经验分享作者们也可以了解该流程并完成其中的部分甚至全部步骤。</p><h2 id="预先准备" tabindex="-1">预先准备 <a class="header-anchor" href="#预先准备" aria-label="Permalink to &quot;预先准备&quot;">​</a></h2><ul><li>创建自己的 fork，并 clone 到本地</li><li>安装一个 Node.js 包管理器，飞跃手册建议使用 <a href="https://bun.sh" target="_blank" rel="noreferrer">Bun</a>，请查看 Bun 文档以了解安装方法。</li><li>进入仓库所在的文件夹，并安装依赖：<code>bun install</code></li><li>推荐审稿人使用 <a href="https://code.visualstudio.com" target="_blank" rel="noreferrer">VSCode</a> 来编辑文件。本项目仓库中已经预置了 VSCode 推荐配置和推荐的插件，请安装推荐的插件以实现所有功能。</li></ul><h2 id="稿件提交" tabindex="-1">稿件提交 <a class="header-anchor" href="#稿件提交" aria-label="Permalink to &quot;稿件提交&quot;">​</a></h2><p>作者可能以两种方式提交稿件：</p><ul><li>直接提交 PR，此种情况下，直接在 PR 上进行工作即可。</li><li>将帖子文件发送给维护团队，文件格式可能为： <ul><li>Markdown 文件</li><li>其他类型</li></ul></li></ul><p>作者提交的文件不为 Markdown 格式的，应先转换为 Markdown 格式。可用的工具包括微软开发的 <a href="https://github.com/microsoft/markitdown" target="_blank" rel="noreferrer">MarkItDown</a> 和其他各种基于生成式 AI 的工具等。</p><p>如作者已提交了 PR，维护者可通过 <a href="https://cli.github.com" target="_blank" rel="noreferrer">GitHub 命令行工具</a>快速地切换到 PR 分支进行后续工作。安装该工具并配置完成后，可进行如下操作：</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 列出仓库中的 PR</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 切换到指定的 PR</span></span></code></pre></div><p>其他情况下，需要维护者手动创建 PR：</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> post/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upstream/master</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 从上游仓库的主分支建立新分支</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 将文件放置在合适的位置</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">s</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 将新增的文件添加到 staging area</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;add files for ...&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 提交更改，始终填写有意义的 commit message</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upstream</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> post/id</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 创建 PR，注意目标为上游仓库的主分支</span></span></code></pre></div><p>建议在添加了第一个 commit 之后就及时提交 PR，以方便团队协作和查看预览。</p><h2 id="添加元数据" tabindex="-1">添加元数据 <a class="header-anchor" href="#添加元数据" aria-label="Permalink to &quot;添加元数据&quot;">​</a></h2><p>除了内容之外，也应该参考<a href="./metadata">元数据</a>文档，在帖子中添加元数据。</p><h2 id="prettier-格式化" tabindex="-1">Prettier 格式化 <a class="header-anchor" href="#prettier-格式化" aria-label="Permalink to &quot;Prettier 格式化&quot;">​</a></h2><p>飞跃手册使用 <a href="https://prettier.io" target="_blank" rel="noreferrer">Prettier</a> 格式化所有代码和帖子以确保代码质量与可维护性。你可以通过运行 <code>bun run format</code> 来检查是否有文件存在格式问题。如果你正确配置了 VSCode，未被正确格式化的文档将会提示问题，且文件会在被保存时就自动格式化。</p><h2 id="盘古格式化" tabindex="-1">盘古格式化 <a class="header-anchor" href="#盘古格式化" aria-label="Permalink to &quot;盘古格式化&quot;">​</a></h2><p>除了使用 Prettier 进行格式化外，还应该使用「盘古」进行格式化，即在中文汉字和西文字母之间插入空格，以提升阅读体验。VSCode 中有许多插件执行这个功能，这里并不指定使用的插件，作者和审稿人可自行以 &quot;pangu&quot; 为关键词搜索。</p><h2 id="markdown-lint" tabindex="-1">Markdown Lint <a class="header-anchor" href="#markdown-lint" aria-label="Permalink to &quot;Markdown Lint&quot;">​</a></h2><p>除了格式化之外，本项目还使用 <a href="https://github.com/DavidAnson/markdownlint" target="_blank" rel="noreferrer">Markdown Lint</a> 来确保 Markdown 文件符合一定的行文规范，提升用户的阅读体验。你可以通过运行 <code>bun run lint:md</code> 来检查是否有贴文有 Markdown 格式问题。</p><p>除了 Markdown Lint 中明确列出的规则之外，作者和审稿人也可以做出其他的调整，以提升读者的阅读体验。例如：</p><ul><li>短句子并列的，应该使用有序或无序列表</li><li>长段落并列的，应使用小标题而非列表</li><li>非引用内容，则不应该使用普通引用</li><li>作者需要强调段落的，可以适时地使用 callout</li><li>正确使用超链接</li><li>使用相对路径而非绝对路径引用其他贴文</li><li>...</li></ul><h2 id="拼写检查" tabindex="-1">拼写检查 <a class="header-anchor" href="#拼写检查" aria-label="Permalink to &quot;拼写检查&quot;">​</a></h2><p>为了确保文档的准确性，我们还使用 <a href="https://cspell.org" target="_blank" rel="noreferrer">cSpell</a> 进行拼写检查。你可以通过运行 <code>bun run spellcheck</code> 来检查文档中的拼写错误。如果有正确的单词被识别为拼写错误（这种情况在缩写中尤为常见），需要手动将他们加入字典中，即需要在文档中（推荐在这个词第一次使用的段落前）添加一行注释：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">&lt;!-- cSpell:words UAB UCD UEF --&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">我申请了这几个学校：UAB、UCD、UEF……</span></span></code></pre></div><p>通过这行注释，文中提到的单词将会被正确识别。一些会被大量重复使用的单词（如 <code>sustech</code>、<code>SDIM</code>），可以将他们添加到项目的全局字典 <code>words.txt</code> 文件中。</p><h2 id="其他注意事项" tabindex="-1">其他注意事项 <a class="header-anchor" href="#其他注意事项" aria-label="Permalink to &quot;其他注意事项&quot;">​</a></h2><ul><li>由于新版网站不再依赖于标题进行导航且可以通过元数据显示更丰富的内容，作者现在可以为经验分享起更有意义的标题，而不再只是列举年纪、地区、学校、专业等。审稿人应该鼓励作者起更有描述性、趣味性的标题。</li><li>持续集成系统会自动检查各种错误，如果出错，可查看日志了解具体原因。</li></ul><h2 id="帖子发布" tabindex="-1">帖子发布 <a class="header-anchor" href="#帖子发布" aria-label="Permalink to &quot;帖子发布&quot;">​</a></h2><p>审稿人确认无误后，应将预览链接发送给原作者，请他们确认最终呈现效果。如无误，审稿人可申请其他维护者进行 code review，批准后，审稿人即可选择合并 PR，新帖子自动上线。</p>`,32)])])}const g=a(l,[["render",n]]);export{c as __pageData,g as default};
